/**
 * Address-format-v2 codec parity (TS `@botho/core` ⇄ Rust shared codec / node).
 *
 * `@botho/core`'s `formatAddress` / `parseAddress` encode and decode the v2
 * base58 body `view(32)‖spend(32)‖kem(1184)‖dsa(1952)`. That layout MUST be
 * byte-identical to the shared Rust `address-codec` (and therefore to every
 * botho://2/ address the node emits), or a browser-parsed recipient key or a
 * displayed address would drift from the chain.
 *
 * The golden below is produced by the Rust side for the canonical BIP39 test
 * mnemonic ("abandon…about"): both the wasm-signer's `derive_address_from_seed`
 * unit test and the node's own `WalletKeys::public_address_string` emit exactly
 * this string (verified in this PR). Decoding it here with `parseAddress` and
 * recovering the same classical keys proves the TS codec agrees with the node.
 */

import { describe, it, expect } from 'vitest'
import { parseAddress, formatAddress, isValidAddress } from './address'

// GOLDEN: the testnet v2 address the node derives for the canonical BIP39
// "abandon abandon … about" mnemonic. Generated by the Rust
// `bth-wasm-signer` unit test `v2_address_from_seed_matches_node_derivation`
// and cross-checked against `botho-wallet`'s `WalletKeys::public_address_string`.
const GOLDEN_TESTNET_ADDRESS =
  'tbotho:'

// Classical default-subaddress keys the node derives for that mnemonic
// (also asserted by `derivation-parity.test.ts`).
const EXPECTED_VIEW_HEX = '60eeebc23d5d4fa3b90621292da88f39c6df05114bd405319cf9adc905905773'
const EXPECTED_SPEND_HEX = '8e2cf7239559d62c6ca0c0718eac345da1fa9348aa741a94d6489025a05a917c'

function toHex(bytes: Uint8Array): string {
  return Array.from(bytes)
    .map((b) => b.toString(16).padStart(2, '0'))
    .join('')
}

describe('address v2 codec parity (TS <-> Rust/node)', () => {
  it('decodes the node golden into the right components', () => {
    const parsed = parseAddress(GOLDEN_TESTNET_ADDRESS)
    expect(parsed.network).toBe('testnet')
    expect(toHex(parsed.viewPublic)).toBe(EXPECTED_VIEW_HEX)
    expect(toHex(parsed.spendPublic)).toBe(EXPECTED_SPEND_HEX)
    expect(parsed.kemPublic).toHaveLength(1184)
    expect(parsed.dsaPublic).toHaveLength(1952)
  })

  it('re-encodes the decoded golden to the identical string (round-trip)', () => {
    const parsed = parseAddress(GOLDEN_TESTNET_ADDRESS)
    const reencoded = formatAddress(
      parsed.viewPublic,
      parsed.spendPublic,
      parsed.kemPublic,
      parsed.dsaPublic,
      'testnet',
    )
    expect(reencoded).toBe(GOLDEN_TESTNET_ADDRESS)
  })

  it('accepts the golden as a valid address', () => {
    expect(isValidAddress(GOLDEN_TESTNET_ADDRESS)).toBe(true)
  })

  it('mainnet uses the same body under a different prefix', () => {
    const parsed = parseAddress(GOLDEN_TESTNET_ADDRESS)
    const mainnet = formatAddress(
      parsed.viewPublic,
      parsed.spendPublic,
      parsed.kemPublic,
      parsed.dsaPublic,
      'mainnet',
    )
    expect(mainnet.startsWith('botho://2/')).toBe(true)
    expect(mainnet.slice('botho://2/'.length)).toBe(
      GOLDEN_TESTNET_ADDRESS.slice('tbotho://2/'.length),
    )
  })

  it('rejects retired v1 and quantum prefixes loudly', () => {
    expect(() => parseAddress('botho://1/abc')).toThrow(/v1/)
    expect(() => parseAddress('tbotho://1/abc')).toThrow(/v1/)
    expect(() => parseAddress('botho://1q/abc')).toThrow(/[Qq]uantum/)
    expect(() => parseAddress('botho-pq://1/abc')).toThrow(/[Qq]uantum/)
  })
})
